// ─── Medication Progress Ring ──────────────────────────────────
function MedProgress({ taken, total, pct, colors }: { taken: number; total: number; pct: number; colors: any }) {
  // circumference calculation
  const size = 70;
  const strokeWidth = 5;
  const radius = (size - strokeWidth) / 2;
  const circumference = 2 * Math.PI * radius;

  // Safe stroke dash offset calculation for web (avoids Reanimated crash)
  const offset = circumference - (circumference * pct) / 100;

  return (
    <View style={mp.wrap}>
      {/* Left: ring + number */}
      <View style={mp.ringWrap}>
        <Svg width={size} height={size}>
          <SvgCircle
            cx={size / 2}
            cy={size / 2}
            r={radius}
            stroke={colors.border}
            strokeWidth={strokeWidth}
            fill="none"
          />
          <SvgCircle
            cx={size / 2}
            cy={size / 2}
            r={radius}
            stroke={colors.clay}
            strokeWidth={strokeWidth}
            fill="none"
            strokeDasharray={circumference}
            strokeDashoffset={offset}
            strokeLinecap="round"
            style={{ transform: [{ rotate: "-90deg" }], transformOrigin: "center" }}
          />
        </Svg>
        <View style={mp.ringInnerAbs}>
          <Text style={[mp.ringPct, { color: colors.foreground }]}>{pct}%</Text>
          <Text style={[mp.ringLabel, { color: colors.inkMuted }]}>done</Text>
        </View>
      </View>
      {/* Right: facts */}
      <View style={mp.facts}>
        <Text style={[mp.factsTitle, { color: colors.foreground }]}>Today's Medications</Text>
        <Text style={[mp.factsSub, { color: colors.inkMuted }]}>
          {taken} of {total} taken · {total - taken} remaining
        </Text>
        <View style={[mp.progressBar, { backgroundColor: colors.border }]}>
          <Animated.View style={[mp.progressFill, { backgroundColor: colors.clay }, useAnimatedStyle(() => ({ width: withTiming(`${pct}%`, { duration: 600 }) }))]} />
        </View>
      </View>
    </View>
  );
}

const mp = StyleSheet.create({
  wrap: { flexDirection: "row", alignItems: "center", gap: 18, padding: 18 },
  ringWrap: { width: 70, height: 70 },
  ringInnerAbs: {
    position: "absolute",
    width: 70, height: 70,
    alignItems: "center", justifyContent: "center",
  },
  ringPct: { fontSize: 16, fontFamily: "Fraunces_500Medium", letterSpacing: -0.3 },
  ringLabel: { fontSize: 9, fontFamily: "DMSans_400Regular", letterSpacing: 0.5 },
  facts: { flex: 1, gap: 6 },
  factsTitle: { fontSize: 15, fontFamily: "DMSans_600SemiBold", letterSpacing: -0.2 },
  factsSub: { fontSize: 12, fontFamily: "DMSans_400Regular" },
  progressBar: { height: 4, borderRadius: 2, overflow: "hidden" },
  progressFill: { height: 4, borderRadius: 2 },
});

// ─── Animated Medication Row ────────────────────────────────────
function MedRow({ med, isLast, colors, delay, onToggle }: { med: any; isLast: boolean; colors: any; delay: number; onToggle: (id: string, next: boolean) => void }) {
  const taken = med.taken;

  // Row bounce on press
  const rowScale = useSharedValue(1);
  // Checkbox fill scale (0 → hidden, 1 → visible)
  const checkScale = useSharedValue(taken ? 1 : 0);
  // Checkbox border/bg opacity for colour shift
  const checkProgress = useSharedValue(taken ? 1 : 0);

  const toggle = useCallback(() => {
    const next = !taken;
    onToggle(med.id, next);

    // Row bounce
    rowScale.value = withSequence(
      withTiming(0.97, { duration: 70 }),
      withSpring(1, { damping: 12, stiffness: 200 })
    );

    // Animate checkmark in or out
    checkScale.value = next
      ? withSequence(withTiming(0, { duration: 60 }), withSpring(1, { damping: 8, stiffness: 260 }))
      : withTiming(0, { duration: 150 });

    checkProgress.value = withTiming(next ? 1 : 0, { duration: 200 });
  }, [taken]);

  const rowStyle = useAnimatedStyle(() => ({
    transform: [{ scale: rowScale.value }],
  }));

  const checkFillStyle = useAnimatedStyle(() => ({
    transform: [{ scale: checkScale.value }],
    opacity: checkScale.value,
  }));

  const checkWrapStyle = useAnimatedStyle(() => ({
    backgroundColor: `rgba(182,120,92,${checkProgress.value * 0.14})`,
    borderColor: checkProgress.value > 0.5 ? colors.clay : colors.border,
  }));

  // Time-of-day badge colour
  const hour = parseInt(med.time?.split(":")[0] ?? "8", 10);
  const timeBg = hour < 12 ? "#FFF4DC" : "#E8F5E9";
  const timeColor = hour < 12 ? "#B8860B" : "#388E3C";

  return (
    <Animated.View
      entering={FadeInDown.duration(350).delay(delay)}
      style={[
        rowStyle,
        mr.row,
        !isLast && { borderBottomWidth: StyleSheet.hairlineWidth, borderBottomColor: colors.border },
      ]}
    >
      {/* Animated checkbox */}
      <Pressable onPress={toggle} hitSlop={10}>
        <Animated.View style={[mr.checkWrap, checkWrapStyle]}>
          {/* Always rendered, animated in/out via scale */}
          <Animated.View style={[mr.checkFill, { backgroundColor: colors.clay }, checkFillStyle]}>
            <Text style={mr.checkMark}>✓</Text>
          </Animated.View>
        </Animated.View>
      </Pressable>

      {/* Med info */}
      <View style={mr.info}>
        <Text
          style={[
            mr.name,
            { color: taken ? colors.inkMuted : colors.foreground },
            taken && mr.nameStruck,
          ]}
        >
          {med.name}
        </Text>
        <Text style={[mr.sub, { color: colors.inkMuted }]}>
          {med.dosage}{"  ·  "}{med.time}
        </Text>
        {/* Prescribed by + reason */}
        <View style={mr.rxRow}>
          <Text style={[mr.rxText, { color: colors.clay }]}>{med.prescribedBy}</Text>
          <Text style={[mr.rxDot, { color: colors.border }]}>·</Text>
          <Text style={[mr.rxReason, { color: colors.inkMuted }]}>{med.reason}</Text>
        </View>
      </View>

      {/* Time badge */}
      <View style={[mr.timeBadge, { backgroundColor: timeBg }]}>
        <Text style={[mr.timeText, { color: timeColor }]}>{med.frequency}</Text>
      </View>
    </Animated.View>
  );
}

const mr = StyleSheet.create({
  row: { flexDirection: "row", alignItems: "center", gap: 14, paddingHorizontal: 16, paddingVertical: 14 },
  checkWrap: {
    width: 34, height: 34, borderRadius: 11, borderWidth: 1.5,
    alignItems: "center", justifyContent: "center",
  },
  checkFill: {
    width: 22, height: 22, borderRadius: 7,
    alignItems: "center", justifyContent: "center",
  },
  checkMark: { color: "#fff", fontSize: 13, fontFamily: "DMSans_600SemiBold" },
  info: { flex: 1, gap: 2 },
  name: { fontSize: 14, fontFamily: "DMSans_600SemiBold", letterSpacing: -0.2 },
  nameStruck: { textDecorationLine: "line-through", opacity: 0.5 },
  sub: { fontSize: 12, fontFamily: "DMSans_400Regular" },
  rxRow: { flexDirection: "row", alignItems: "center", gap: 5, marginTop: 2 },
  rxText: { fontSize: 11, fontFamily: "DMSans_500Medium" },
  rxDot: { fontSize: 11 },
  rxReason: { fontSize: 11, fontFamily: "DMSans_400Regular", flex: 1 },
  timeBadge: { borderRadius: 10, paddingHorizontal: 9, paddingVertical: 5 },
  timeText: { fontSize: 10, fontFamily: "DMSans_600SemiBold", letterSpacing: 0.3 },
});

